""0"",""isLinked"":false}},""elements"":[],""widgetType"":""heading""}],""isInner"":false}],""isInner"":false},{""id"":""05d6c65"",""elType"":""section"",""settings"":[],""elements"":[{""id"":""60d81f2"",""elType"":""column"",""settings"":{""_column_size"":100,""_inline_size"":null},""elements"":[{""id"":""459521e"",""elType"":""widget"",""settings"":{""html"":""<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Hosting Features</title>
  <style>
    body {
      font-family: Arial, sans-serif;
      line-height: 1.6;
      margin: 0;
      padding: 0;
      background-color: #f9fcff;
      overflow-x: hidden;
    }

    .section {
      padding: 40px 20px;
      max-width: 1000px;
      margin: auto;
    }

    .feature-box {
      background-color: #e9f7ff;
      padding: 30px;
      border-radius: 16px;
      display: flex;
      align-items: center;
      gap: 30px;
      flex-wrap: wrap;
      margin-bottom: 60px;
      box-sizing: border-box;
    }

    .feature-box img {
      width: 100%;
      max-width: 300px;
      height: auto;
      flex-shrink: 0;
    }

    .feature-text {
      flex: 1;
      min-width: 250px;
    }

    .feature-text h2 {
      margin-top: 0;
      color: #083a6e;
    }

    .feature-text p {
      color: #333;
    }

    @media (max-width: 768px) {
      .feature-box,
      .terminal-section {
        flex-direction: column;
        text-align: center;
      }

      .feature-text,
      .terminal-section .text {
        width: 100%;
      }

      .feature-box img,
      .terminal-section img {
        margin: 0 auto;
      }
    }
  </style>
</head>
<body>

  <div class="section">
    <div class="feature-box">
      <img src="https://www.fyphost.com/wp-content/uploads/2025/05/images__21_-removebg-preview.png" alt="Control Panel Logos">
      <div class="feature-text">
       <h2> Experience Unmatched Performance with Next-Gen Intel Power</h2>
       <p>Our top-tier VPS hosting solutions are engineered and rigorously tested on the latest Intel processors and chipsets before launch—ensuring blazing-fast performance and reliability from day one</p>

      </div>
   </div>
</body>
</html>"",""_margin"":{""unit"":""px"",""top"":""-30"",""right"":""0"",""bottom"":""-90"",""left"":""0"",""isLinked"":false},""_margin_mobile"":{""unit"":""px"",""top"":""0"",""right"":""0"",""bottom"":""-80"",""left"":""0"",""isLinked"":false},""_background_color_stop_tablet"":{""unit"":""%""},""_background_color_stop_mobile"":{""unit"":""%""},""_background_color_b_stop_tablet"":{""unit"":""%""},""_background_color_b_stop_mobile"":{""unit"":""%""},""_background_gradient_angle_tablet"":{""unit"":""deg""},""_background_gradient_angle_mobile"":{""unit"":""deg""},""_background_hover_color_stop_tablet"":{""unit"":""%""},""_background_hover_color_stop_mobile"":{""unit"":""%""},""_background_hover_color_b_stop_tablet"":{""unit"":""%""},""_background_hover_color_b_stop_mobile"":{""unit"":""%""},""_background_hover_gradient_angle_tablet"":{""unit"":""deg""},""_background_hover_gradient_angle_mobile"":{""unit"":""deg""}},""elements"":[],""widgetType"":""html""}],""isInner"":false}],""isInner"":false},{""id"":""38c26fd"",""elType"":""section"",""settings"":[],""elements"":[{""id"":""6fd4b3c"",""elType"":""column"",""settings"":{""_column_size"":100,""_inline_size"":null},""elements"":[{""id"":""0c98043"",""elType"":""widget"",""settings"":{""html"":""<!DOCTYPE html>
